unsafe_example:
// UNSAFE: raw user input as the path
string filename = Request.Query["file"];
string content = File.ReadAllText(filename);

// UNSAFE: Path.Combine does NOT protect against ..
string full = Path.Combine(baseDir, Request.Query["file"]);
File.ReadAllText(full);

safe_example:
// SAFE: strip directory, resolve, and verify containment
string filename = Request.Query["file"];
string safe = Path.GetFileName(filename);
string baseDir = Path.GetFullPath("/var/data/reports");
string full = Path.GetFullPath(Path.Combine(baseDir, safe));
if (!full.StartsWith(baseDir + Path.DirectorySeparatorChar))
    throw new SecurityException("path escape");
string content = File.ReadAllText(full);
